import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { 
  Shirt, 
  Upload, 
  RotateCcw, 
  Plus, 
  Wand2, 
  X, 
  Loader2, 
  ShoppingBag, 
  Tag, 
  Smartphone, 
  Camera, 
  Sparkles,
  ChevronRight,
  ChevronLeft,
  CheckCircle2,
  Download,
  Copy,
  History,
  ArrowLeft,
  AlertCircle,
  Scan,
  User,
  Info
} from 'lucide-react';
import { QRCodeSVG } from 'qrcode.react';
import ThreeViewer from './components/ThreeViewer';
import { ProductState, DesignIdea } from './types';
import { getDesignSuggestions, editLogoWithAI } from './services/geminiService';

const PRESETS: Partial<ProductState>[] = [
  { type: 'polo', color: '#F9FAFB', size: 'L' },
  { type: 'shirt', color: '#111111', size: 'M' },
  { type: 'long_sleeve', color: '#2563EB', size: 'XL' },
  { type: 'hoodie', color: '#6B1010', size: 'L' },
  { type: 'polo', color: '#0D9488', size: 'S' },
];

const CATALOG_ITEMS = [
  { id: 1, name: 'Essential Polo', type: 'polo' as const, price: '$72', image: 'https://images.unsplash.com/photo-1586363104862-3a5e2ab60d99?auto=format&fit=crop&q=80&w=800' },
  { id: 2, name: 'Heavyweight Hoodie', type: 'hoodie' as const, price: '$120', image: 'https://images.unsplash.com/photo-1556821840-3a63f95609a7?auto=format&fit=crop&q=80&w=800' },
  { id: 3, name: 'Street Oversize Tee', type: 'shirt' as const, price: '$55', image: 'https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?auto=format&fit=crop&q=80&w=800' },
  { id: 4, name: 'Tech Long Sleeve', type: 'long_sleeve' as const, price: '$85', image: 'https://images.unsplash.com/photo-1516762689617-e1cffcef479d?auto=format&fit=crop&q=80&w=800' },
];

const ARView: React.FC<{ state: ProductState; onBack: () => void }> = ({ state, onBack }) => {
  const videoRef = React.useRef<HTMLVideoElement>(null);
  const [captured, setCaptured] = useState(false);
  const [cameraStatus, setCameraStatus] = useState<'requesting' | 'active' | 'denied' | 'not-found'>('requesting');
  const [calibrationStep, setCalibrationStep] = useState(0);

  useEffect(() => {
    let stream: MediaStream | null = null;

    async function startCamera() {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setCameraStatus('not-found');
        return;
      }

      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { 
            facingMode: 'user',
            width: { ideal: 1280 },
            height: { ideal: 720 }
          }, 
          audio: false 
        });

        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          setCameraStatus('active');
          // Start calibration sequence
          setTimeout(() => setCalibrationStep(1), 1500);
          setTimeout(() => setCalibrationStep(2), 3500);
        }
      } catch (err: any) {
        console.error("Camera access error:", err);
        if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
          setCameraStatus('denied');
        } else {
          setCameraStatus('not-found');
        }
      }
    }

    startCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const handleCapture = () => {
    if (cameraStatus !== 'active') return;
    setCaptured(true);
    setTimeout(() => setCaptured(false), 2000);
  };

  const instructions = [
    "Initializing Neural Fabric Scan...",
    "Align your shoulders with the guides.",
    "Adjust distance for optimal fit."
  ];

  return (
    <div className="fixed inset-0 z-[100] bg-black overflow-hidden flex flex-col animate-in fade-in duration-500">
      {/* Background Layer (Camera or Gradient) */}
      <div className="absolute inset-0 z-0">
        {cameraStatus === 'active' ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className="w-full h-full object-cover opacity-60"
            />
            {/* Scan Line Animation */}
            <div className="absolute left-0 w-full h-1 bg-indigo-500/50 blur-[2px] shadow-[0_0_15px_rgba(79,70,229,0.8)] z-10 animate-[scan_4s_ease-in-out_infinite]" />
            <style>{`
              @keyframes scan {
                0% { top: 10%; opacity: 0; }
                10% { opacity: 1; }
                90% { opacity: 1; }
                100% { top: 90%; opacity: 0; }
              }
            `}</style>
          </>
        ) : (
          <div className="w-full h-full bg-gradient-to-br from-zinc-900 to-black flex flex-col items-center justify-center p-10 text-center">
            {cameraStatus === 'requesting' ? (
              <div className="flex flex-col items-center gap-4">
                <Loader2 className="w-10 h-10 text-indigo-500 animate-spin" />
                <p className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40 italic">Initializing Optical Feed...</p>
              </div>
            ) : (
              <div className="max-w-xs animate-in zoom-in-95 duration-500">
                <AlertCircle className="w-12 h-12 text-red-500 mx-auto mb-6" />
                <h3 className="text-xl font-black italic tracking-tighter uppercase mb-2">
                  {cameraStatus === 'denied' ? 'Access Denied' : 'Lens Not Found'}
                </h3>
                <p className="text-[10px] font-bold text-white/40 uppercase tracking-widest leading-relaxed">
                  {cameraStatus === 'denied' 
                    ? 'Please enable camera permissions in your browser settings to continue with spatial try-on.' 
                    : 'We could not detect a valid camera source. This feature requires a front-facing camera.'}
                </p>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Visual Alignment Guides (Dashed Box & Shoulder Markers) */}
      {cameraStatus === 'active' && (
        <div className="absolute inset-0 z-10 pointer-events-none flex items-center justify-center">
          <div className="w-[80%] max-w-md aspect-[3/4] relative">
            {/* Corners */}
            <div className="absolute top-0 left-0 w-12 h-12 border-t-2 border-l-2 border-indigo-500/50 rounded-tl-3xl" />
            <div className="absolute top-0 right-0 w-12 h-12 border-t-2 border-r-2 border-indigo-500/50 rounded-tr-3xl" />
            <div className="absolute bottom-0 left-0 w-12 h-12 border-b-2 border-l-2 border-indigo-500/50 rounded-bl-3xl" />
            <div className="absolute bottom-0 right-0 w-12 h-12 border-b-2 border-r-2 border-indigo-500/50 rounded-br-3xl" />

            {/* Shoulder Alignment Dots */}
            <div className="absolute top-[25%] left-[10%] flex flex-col items-center gap-2 animate-pulse">
              <div className="w-3 h-3 bg-white/40 rounded-full border border-white/20" />
              <span className="text-[7px] text-white/40 font-black uppercase tracking-widest">Left Shoulder</span>
            </div>
            <div className="absolute top-[25%] right-[10%] flex flex-col items-center gap-2 animate-pulse">
              <div className="w-3 h-3 bg-white/40 rounded-full border border-white/20" />
              <span className="text-[7px] text-white/40 font-black uppercase tracking-widest">Right Shoulder</span>
            </div>

            {/* Silhouette Hint */}
            <div className="absolute inset-x-0 bottom-0 top-[20%] border-x-2 border-dashed border-white/5 mx-[15%] rounded-t-[120px]" />
          </div>
        </div>
      )}

      {/* Main UI Overlay - The Product */}
      <div className="relative z-10 flex-1 flex items-center justify-center p-10 pointer-events-none">
        <div className={`w-full h-full max-w-lg aspect-[3/4] pointer-events-auto transition-all duration-1000 ${calibrationStep === 0 ? 'opacity-0 scale-90 blur-xl' : 'opacity-100 scale-100 blur-0'}`}>
           <ThreeViewer state={state} />
        </div>
      </div>

      {/* Floating Instruction Banner */}
      {cameraStatus === 'active' && (
        <div className="absolute top-24 left-1/2 -translate-x-1/2 z-30 w-full max-w-xs animate-in slide-in-from-top-4 duration-700">
           <div className="bg-black/60 backdrop-blur-3xl border border-white/10 rounded-2xl p-4 flex items-center gap-4 shadow-2xl">
             <div className="w-8 h-8 rounded-xl bg-indigo-500/20 flex items-center justify-center">
               {calibrationStep === 0 ? <Scan className="w-4 h-4 text-indigo-400 animate-spin" /> : <User className="w-4 h-4 text-indigo-400" />}
             </div>
             <div>
               <p className="text-[8px] font-black uppercase tracking-[0.2em] text-white/40 mb-1">Optical Guide</p>
               <p className="text-[11px] font-black uppercase tracking-wider text-white italic">{instructions[calibrationStep]}</p>
             </div>
           </div>
        </div>
      )}

      {/* Control Bar */}
      <div className="relative z-20 p-8 flex justify-between items-center bg-gradient-to-t from-black via-black/80 to-transparent">
        <button 
          onClick={onBack}
          className="px-8 py-4 bg-white/10 backdrop-blur-xl border border-white/20 rounded-full text-xs font-black uppercase tracking-widest hover:bg-white/20 transition-all flex items-center gap-3"
        >
          <ChevronLeft className="w-4 h-4" />
          Back to Studio
        </button>

        <button 
          onClick={handleCapture}
          disabled={cameraStatus !== 'active'}
          className={`p-6 bg-white rounded-full shadow-[0_0_30px_rgba(255,255,255,0.3)] hover:scale-110 active:scale-90 transition-all disabled:opacity-30 disabled:grayscale disabled:scale-100 relative group overflow-hidden`}
        >
          {captured ? (
            <CheckCircle2 className="w-6 h-6 text-green-600 animate-in zoom-in-50" />
          ) : (
            <Camera className="w-6 h-6 text-black" />
          )}
          <div className="absolute inset-0 bg-indigo-500/10 scale-0 group-hover:scale-100 transition-transform duration-500 rounded-full" />
        </button>

        <button 
          className="px-8 py-4 bg-white/5 backdrop-blur-xl border border-white/10 rounded-full text-[9px] font-black uppercase tracking-widest text-white/40 hover:text-white transition-all flex items-center gap-2"
          onClick={() => setCalibrationStep(0)}
        >
          <RotateCcw className="w-3 h-3" />
          Recalibrate
        </button>
      </div>

      {/* HUD Info */}
      <div className="absolute top-10 left-10 z-20 pointer-events-none hidden md:block">
        <div className="flex items-center gap-3 bg-black/40 backdrop-blur-md px-5 py-3 rounded-2xl border border-white/10">
          <div className={`w-2 h-2 rounded-full ${cameraStatus === 'active' ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
          <span className="text-[9px] font-black uppercase tracking-[0.4em] text-white/60 italic">
            {cameraStatus === 'active' ? 'SPATIAL_LINK: ACTIVE' : 'SPATIAL_LINK: OFFLINE'}
          </span>
        </div>
      </div>

      <div className="absolute top-10 right-10 z-20 pointer-events-none hidden md:flex items-center gap-3 bg-black/40 backdrop-blur-md px-5 py-3 rounded-2xl border border-white/10">
        <Info className="w-3 h-3 text-white/40" />
        <span className="text-[9px] font-black uppercase tracking-[0.4em] text-white/60">Auto-Calibration Engine v2.4</span>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'catalog' | 'studio' | 'archive'>('studio');
  const [isARMode, setIsARMode] = useState(false);

  const [product, setProduct] = useState<ProductState>(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#ar-view')) {
      try {
        const urlParams = new URLSearchParams(hash.split('?')[1]);
        const stateParam = urlParams.get('state');
        if (stateParam) {
          return JSON.parse(atob(stateParam));
        }
      } catch (e) { 
        console.error("Failed to parse state from URL"); 
      }
    }
    return {
      type: 'polo',
      size: 'L',
      color: '#F9FAFB',
      logos: { front: null, back: null, leftSleeve: null, rightSleeve: null },
      textureIntensity: 0.5
    };
  });

  useEffect(() => {
    const handleHashChange = () => {
      const isAR = window.location.hash.startsWith('#ar-view');
      setIsARMode(isAR);
    };
    handleHashChange(); // Initial check
    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const [aiSuggestions, setAiSuggestions] = useState<DesignIdea[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [activeTab, setActiveTab] = useState<'basics' | 'design' | 'presets'>('basics');
  const [showQR, setShowQR] = useState(false);
  const [editingPos, setEditingPos] = useState<keyof ProductState['logos'] | null>(null);
  const [editPrompt, setEditPrompt] = useState('');
  const [isEditingImage, setIsEditingImage] = useState(false);
  const [orderStatus, setOrderStatus] = useState<'idle' | 'processing' | 'success'>('idle');
  const [copyFeedback, setCopyFeedback] = useState(false);
  const [savedDesigns, setSavedDesigns] = useState<ProductState[]>([]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, position: keyof ProductState['logos']) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setProduct(prev => ({
          ...prev,
          logos: { ...prev.logos, [position]: event.target?.result as string }
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAIImageEdit = async () => {
    if (!editingPos || !product.logos[editingPos] || !editPrompt) return;
    setIsEditingImage(true);
    const editedImage = await editLogoWithAI(product.logos[editingPos]!, editPrompt);
    if (editedImage) {
      setProduct(prev => ({ ...prev, logos: { ...prev.logos, [editingPos]: editedImage } }));
      setEditingPos(null);
      setEditPrompt('');
    }
    setIsEditingImage(false);
  };

  const handleGenerateIdeas = async () => {
    setIsGenerating(true);
    try {
      const ideas = await getDesignSuggestions('Premium Minimalism, High-Contrast Geometric, Cyberpunk Subtle');
      if (Array.isArray(ideas)) {
        setAiSuggestions(ideas);
      }
    } catch (err) {
      console.error(err);
    }
    setIsGenerating(false);
  };

  const handleSnapshot = () => {
    const canvas = document.querySelector('canvas');
    if (canvas) {
      const link = document.createElement('a');
      link.download = `picknprints-4k-render-${Date.now()}.png`;
      link.href = canvas.toDataURL('image/png', 1.0);
      link.click();
    }
  };

  const handleCommitDesign = () => {
    setOrderStatus('processing');
    setTimeout(() => {
      setSavedDesigns(prev => [...prev, JSON.parse(JSON.stringify(product))]);
      setOrderStatus('success');
    }, 2000);
  };

  const shareUrl = useMemo(() => {
    try {
      const sharedProduct = {
        type: product.type,
        size: product.size,
        color: product.color
      };
      const stateStr = btoa(JSON.stringify(sharedProduct));
      const baseUrl = window.location.href.split('#')[0];
      return `${baseUrl}#ar-view?state=${stateStr}`;
    } catch (e) {
      return window.location.href.split('#')[0];
    }
  }, [product.type, product.size, product.color]);

  const handleCopyLink = () => {
    navigator.clipboard.writeText(shareUrl);
    setCopyFeedback(true);
    setTimeout(() => setCopyFeedback(false), 2000);
  };

  const handleExitAR = () => {
    window.location.hash = '';
    setIsARMode(false);
  };

  if (isARMode) {
    return <ARView state={product} onBack={handleExitAR} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-[#050505] text-white font-['Inter'] selection:bg-indigo-600">
      {/* Navigation */}
      <nav className="flex items-center justify-between px-10 py-6 border-b border-white/5 backdrop-blur-3xl sticky top-0 z-50 bg-black/60">
        <div className="flex items-center gap-4 cursor-pointer" onClick={() => setCurrentView('studio')}>
          <div className="bg-white p-2.5 rounded-2xl shadow-xl shadow-white/5 hover:rotate-6 transition-transform">
            <Shirt className="text-black w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase">Pick'n Prints</h1>
            <p className="text-[10px] text-white/30 font-bold uppercase tracking-widest mt-1 italic">Vantage Studio Pro</p>
          </div>
        </div>
        <div className="hidden lg:flex items-center gap-10">
          <button 
            onClick={() => setCurrentView('catalog')}
            className={`text-[10px] font-black uppercase tracking-widest transition-colors relative group ${currentView === 'catalog' ? 'text-white' : 'text-white/40 hover:text-white'}`}
          >
            Catalog
            <span className={`absolute -bottom-1 left-0 h-px bg-white transition-all ${currentView === 'catalog' ? 'w-full' : 'w-0 group-hover:w-full'}`} />
          </button>
          <button 
            onClick={() => setCurrentView('studio')}
            className={`text-[10px] font-black uppercase tracking-widest relative group ${currentView === 'studio' ? 'text-indigo-400' : 'text-white/40 hover:text-white'}`}
          >
            Custom Studio
            <span className={`absolute -bottom-1 left-0 h-px bg-indigo-400 transition-all ${currentView === 'studio' ? 'w-full' : 'w-0 group-hover:w-full'}`} />
          </button>
          <button 
            onClick={() => setCurrentView('archive')}
            className={`text-[10px] font-black uppercase tracking-widest transition-colors relative group ${currentView === 'archive' ? 'text-white' : 'text-white/40 hover:text-white'}`}
          >
            Archive
            <span className={`absolute -bottom-1 left-0 h-px bg-white transition-all ${currentView === 'archive' ? 'w-full' : 'w-0 group-hover:w-full'}`} />
          </button>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden sm:flex items-center gap-2 px-4 py-2 bg-white/5 border border-white/10 rounded-full">
            <Tag className="w-3 h-3 text-white/50" />
            <span className="text-[9px] font-black text-white/50 uppercase">Unlimited Session</span>
          </div>
          <button className="p-3 bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all">
            <ShoppingBag className="w-5 h-5" />
          </button>
        </div>
      </nav>

      {currentView === 'catalog' ? (
        <div className="flex-1 p-12 overflow-y-auto animate-in fade-in duration-700">
          <div className="max-w-7xl mx-auto">
            <div className="flex items-center justify-between mb-12">
              <h2 className="text-5xl lg:text-7xl font-black italic tracking-tighter uppercase leading-none">The Collection</h2>
              <button 
                onClick={() => setCurrentView('studio')}
                className="flex items-center gap-3 px-6 py-4 rounded-full border border-white/10 hover:bg-white/5 transition-all text-[10px] font-black uppercase tracking-[0.3em] text-white/50 hover:text-white"
              >
                <ArrowLeft className="w-4 h-4" />
                Studio
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
              {CATALOG_ITEMS.map((item) => (
                <div key={item.id} className="group cursor-pointer">
                  <div className="relative aspect-[3/4] rounded-[48px] overflow-hidden mb-6 border border-white/5 bg-white/5">
                    <img src={item.image} alt={item.name} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 grayscale group-hover:grayscale-0" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                    <button 
                      onClick={() => {
                        setProduct(prev => ({ ...prev, type: item.type }));
                        setCurrentView('studio');
                      }}
                      className="absolute bottom-10 left-1/2 -translate-x-1/2 px-8 py-4 bg-white text-black text-[10px] font-black uppercase tracking-widest rounded-full opacity-0 translate-y-4 group-hover:opacity-100 group-hover:translate-y-0 transition-all"
                    >
                      Customize This
                    </button>
                  </div>
                  <div className="flex justify-between items-start px-4">
                    <div>
                      <h3 className="text-sm font-black uppercase tracking-widest mb-1">{item.name}</h3>
                      <p className="text-[10px] font-bold text-white/40 uppercase tracking-[0.2em]">Premium Chassis</p>
                    </div>
                    <span className="text-sm font-black italic text-indigo-400">{item.price}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      ) : currentView === 'archive' ? (
        <div className="flex-1 p-12 overflow-y-auto animate-in fade-in duration-700">
          <div className="max-w-7xl mx-auto">
            <div className="flex items-center justify-between mb-12">
              <h2 className="text-5xl lg:text-7xl font-black italic tracking-tighter uppercase leading-none">Your Archives</h2>
              <button 
                onClick={() => setCurrentView('studio')}
                className="flex items-center gap-3 px-6 py-4 rounded-full border border-white/10 hover:bg-white/5 transition-all text-[10px] font-black uppercase tracking-[0.3em] text-white/50 hover:text-white"
              >
                <ArrowLeft className="w-4 h-4" />
                Studio
              </button>
            </div>
             {savedDesigns.length === 0 ? (
               <div className="py-40 text-center">
                 <History className="w-20 h-20 text-white/5 mx-auto mb-10" />
                 <p className="text-white/20 font-black uppercase tracking-[0.4em]">No designs committed yet</p>
                 <button 
                  onClick={() => setCurrentView('studio')}
                  className="mt-10 px-10 py-5 border border-white/10 rounded-full text-[10px] font-black uppercase tracking-[0.4em] hover:bg-white hover:text-black transition-all"
                 >
                   Start Crafting
                 </button>
               </div>
             ) : (
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
                 {savedDesigns.map((design, i) => (
                   <div key={i} className="bg-white/5 border border-white/10 rounded-[48px] p-8 flex flex-col gap-6 group hover:border-indigo-500/30 transition-all">
                      <div className="aspect-square rounded-[32px] overflow-hidden bg-black flex items-center justify-center">
                         <div className="w-3/4 h-3/4 pointer-events-none opacity-80 group-hover:opacity-100 transition-opacity">
                            <ThreeViewer state={design} />
                         </div>
                      </div>
                      <div className="flex justify-between items-end">
                        <div>
                          <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">Build #{Math.random().toString(16).slice(2, 8).toUpperCase()}</p>
                          <h4 className="text-lg font-black uppercase italic tracking-tighter">{design.type.replace('_', ' ')}</h4>
                        </div>
                        <button 
                          onClick={() => { setProduct(design); setCurrentView('studio'); }}
                          className="p-4 bg-white/10 rounded-2xl hover:bg-white hover:text-black transition-all"
                        >
                          <RotateCcw className="w-5 h-5" />
                        </button>
                      </div>
                   </div>
                 ))}
               </div>
             )}
          </div>
        </div>
      ) : (
        <main className="flex-1 grid grid-cols-1 lg:grid-cols-12 overflow-hidden h-auto lg:h-[calc(100vh-85px)] animate-in fade-in duration-700">
          {/* Sidebar Workspace */}
          <div className="lg:col-span-4 p-8 overflow-y-auto border-r border-white/5 bg-[#080808] scrollbar-hide order-2 lg:order-1">
            <div className="max-w-md mx-auto">
