        <button onClick={() => setCaptured(true)} className="p-6 bg-white rounded-full shadow-2xl hover:scale-110 active:scale-90 transition-all">
          <Camera className="w-6 h-6 text-black" />
        </button>
        <div className="w-[120px]" /> 
      </div>

      <div className="absolute top-10 left-10 z-20">
         <div className="flex items-center gap-4 bg-black/50 backdrop-blur-md px-5 py-3 rounded-2xl border border-white/10">
