// Fix: Extend the JSX namespace to include React Three Fiber's intrinsic elements.
// This resolves TypeScript errors where tags like <mesh>, <group>, <meshStandardMaterial>, 
// and various geometries are not recognized in JSX.IntrinsicElements.
declare global {
  namespace JSX {
    interface IntrinsicElements extends ThreeElements {}
  }
}

interface ShirtProps {
  state: ProductState;
}

interface LogoDecalProps {
  url: string;
  position: [number, number, number];
  rotation: [number, number, number];
  scale: number;
}

const LogoDecal: React.FC<LogoDecalProps> = ({ url, position, rotation, scale }) => {
  const texture = useTexture(url);
  return (
    <Decal
      position={position}
      rotation={rotation}
      scale={scale}
    >
      {/* 
        Fix: Move material-specific properties like polygonOffset and polygonOffsetFactor 
        to a child meshStandardMaterial. These properties are not valid on the Decal component itself 
        but are necessary for the material to prevent Z-fighting with the underlying mesh.
      */}
      <meshStandardMaterial
        map={texture}
        transparent
        polygonOffset
        polygonOffsetFactor={-1}
      />
    </Decal>
  );
};

