const ColorAdjustmentPanel: React.FC<{ state: ProductState; onChange: (p: ProductState) => void }> = ({ state, onChange }) => {
  const [adjustTab, setAdjustTab] = useState<'color' | 'saturation' | 'exposure'>('color');
  const canvasRef = useRef<HTMLDivElement>(null);

  const handlePointClick = (e: React.MouseEvent) => {
    if (!canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;

    // In Color tab: X = Hue, Y = Lightness
    // In Saturation tab: X = Saturation
    if (adjustTab === 'color') {
      const h = Math.round(x * 360);
      const l = Math.round((1 - y) * 100);
      const newHex = hslToHex(h, state.saturation, l);
      onChange({ ...state, hue: h, lightness: l, color: newHex });
    } else if (adjustTab === 'saturation') {
      const s = Math.round(x * 100);
      const newHex = hslToHex(state.hue, s, state.lightness);
      onChange({ ...state, saturation: s, color: newHex });
    }
  };

  return (
    <div className="bg-[#1a1a1a] rounded-[32px] border border-white/5 overflow-hidden shadow-2xl animate-in fade-in zoom-in-95 duration-500">
      {/* Tab Header */}
      <div className="flex items-center justify-around p-4 border-b border-white/5 bg-black/20">
        {[
          { id: 'color', icon: Palette, label: 'Color' },
          { id: 'saturation', icon: Droplets, label: 'Saturation' },
          { id: 'exposure', icon: Sun, label: 'Exposure' }
        ].map((t) => (
          <button
            key={t.id}
            onClick={() => setAdjustTab(t.id as any)}
            className={`flex flex-col items-center gap-2 px-6 py-3 rounded-2xl transition-all ${adjustTab === t.id ? 'bg-white/10 text-white' : 'text-white/20 hover:text-white/40'}`}
          >
            <t.icon className={`w-5 h-5 ${adjustTab === t.id ? 'text-indigo-400' : ''}`} />
            <span className="text-[8px] font-black uppercase tracking-widest">{t.label}</span>
          </button>
        ))}
      </div>

      {/* Visual Workspace */}
      <div 
        ref={canvasRef}
        className="relative h-48 cursor-crosshair overflow-hidden group"
        onClick={handlePointClick}
      >
        {adjustTab === 'color' && (
          <div className="w-full h-full bg-gradient-to-r from-red-500 via-yellow-500 via-green-500 via-cyan-500 via-blue-500 via-purple-500 to-red-500 opacity-80" />
        )}
        {adjustTab === 'saturation' && (
          <div className="w-full h-full flex" style={{ background: `linear-gradient(to right, #888, ${state.color})` }} />
        )}
        {adjustTab === 'exposure' && (
          <div className="w-full h-full bg-gradient-to-t from-black via-zinc-800 to-white opacity-90" />
        )}

        {/* Selection Indicator */}
        <div 
          className="absolute w-4 h-4 border-2 border-white rounded-full shadow-2xl pointer-events-none transition-all duration-300"
          style={{ 
            left: `${(state.hue / 360) * 100}%`, 
            top: `${(1 - state.lightness / 100) * 100}%`,
            backgroundColor: state.color
          }}
        />

        {/* Grid Lines */}
        <div className="absolute inset-0 grid grid-cols-6 grid-rows-4 opacity-10 pointer-events-none">
          {[...Array(24)].map((_, i) => <div key={i} className="border-[0.5px] border-white" />)}
        </div>
      </div>

      {/* Stats Readout */}
      <div className="p-6 space-y-4">
        {[
          { label: 'Global', hue: state.hue, val: `${Math.round(state.saturation)}%` },
          { label: 'Shadows', hue: (state.hue + 180) % 360, val: `${Math.round(state.lightness * 0.5)}%` },
          { label: 'Midtones', hue: state.hue, val: `${Math.round(state.lightness)}%` },
          { label: 'Highlights', hue: state.hue, val: `${Math.min(100, Math.round(state.lightness * 1.2))}%` }
        ].map((stat, i) => (
          <div key={i} className="flex items-center justify-between group/stat cursor-default">
            <div className="flex items-center gap-3">
              <div className="w-4 h-4 rounded-full border border-white/10" style={{ backgroundColor: `hsl(${stat.hue}, 70%, 50%)` }} />
              <span className="text-[10px] font-bold text-white/40 uppercase tracking-widest group-hover/stat:text-white transition-colors">{stat.label}</span>
            </div>
            <div className="flex items-center gap-6">
               <span className="text-[10px] font-black italic text-white/20">{stat.hue}°</span>
               <span className="text-[10px] font-black text-indigo-400">{stat.val}</span>
            </div>
          </div>
        ))}
      </div>

      <div className="p-2 border-t border-white/5 bg-black/10 text-center">
         <span className="text-[7px] font-black text-white/10 uppercase tracking-[0.5em]">Spectral Engine v4.0.1</span>
      </div>
    </div>
  );
};

const ARView: React.FC<{ state: ProductState; onBack: () => void }> = ({ state, onBack }) => {
  const videoRef = React.useRef<HTMLVideoElement>(null);
  const [cameraStatus, setCameraStatus] = useState<'requesting' | 'active' | 'denied' | 'not-found'>('requesting');
  const [calibrationStep, setCalibrationStep] = useState(0);

  useEffect(() => {
    let stream: MediaStream | null = null;
    async function startCamera() {
      if (!navigator.mediaDevices?.getUserMedia) {
        setCameraStatus('not-found');
        return;
      }
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } }, 
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          setCameraStatus('active');
          setTimeout(() => setCalibrationStep(1), 1500);
          setTimeout(() => setCalibrationStep(2), 3500);
        }
      } catch (err: any) {
        setCameraStatus(err.name === 'NotAllowedError' ? 'denied' : 'not-found');
      }
    }
    startCamera();
    return () => stream?.getTracks().forEach(track => track.stop());
  }, []);

  return (
    <div className="fixed inset-0 z-[100] bg-black overflow-hidden flex flex-col">
      <div className="absolute inset-0 z-0">
        {cameraStatus === 'active' ? (
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-60" />
        ) : (
          <div className="w-full h-full bg-zinc-900 flex items-center justify-center p-12 text-center">
            <div className="max-w-xs space-y-4">
              {cameraStatus === 'requesting' ? <Loader2 className="w-10 h-10 text-indigo-500 animate-spin mx-auto" /> : <AlertCircle className="w-12 h-12 text-red-500 mx-auto" />}
              <p className="text-[10px] font-black uppercase tracking-widest text-white/50 italic">
                {cameraStatus === 'requesting' ? 'Syncing Optical Feed...' : 'Spatial Link Offline'}
              </p>
            </div>
          </div>
        )}
      </div>

      <div className="relative z-10 flex-1 flex items-center justify-center p-10 pointer-events-none">
        <div className={`w-full h-full max-w-lg aspect-[3/4] transition-all duration-1000 ${calibrationStep === 0 ? 'opacity-0 scale-90 blur-2xl' : 'opacity-100 scale-100 blur-0'}`}>
           <ThreeViewer state={state} />
        </div>
      </div>

      <div className="relative z-20 p-8 flex justify-between items-center bg-gradient-to-t from-black via-black/80 to-transparent">
        <button onClick={onBack} className="px-8 py-4 bg-white/10 backdrop-blur-xl border border-white/20 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-3">
