import React, { useRef, Suspense } from 'react';
import { Canvas, ThreeElements } from '@react-three/fiber';
import { OrbitControls, ContactShadows, Environment, Float, Decal, useTexture } from '@react-three/drei';
import * as THREE from 'three';
import { ProductState } from '../types';

// Fix: Correctly augment the global JSX namespace to include Three.js elements for React Three Fiber
declare global {
  namespace JSX {
    interface IntrinsicElements extends ThreeElements {}
  }
}

interface ShirtProps {
  state: ProductState;
}

interface LogoDecalProps {
  url: string;
  position: [number, number, number];
  rotation: [number, number, number];
  scale: number;
}

const LogoDecal: React.FC<LogoDecalProps> = ({ url, position, rotation, scale }) => {
  const texture = useTexture(url);
  return (
    <Decal
      position={position}
      rotation={rotation}
      scale={scale}
    >
      <meshStandardMaterial
        map={texture}
        transparent
        polygonOffset
        polygonOffsetFactor={-1}
      />
    </Decal>
  );
};

const ShirtModel: React.FC<ShirtProps> = ({ state }) => {
  const meshRef = useRef<THREE.Mesh>(null);

  // Derive color from HSL for smoother live adjustments if hex isn't provided or preferred
  // In our app, we'll sync hex and HSL, but we use hex here for the material
  return (
    <group>
      <mesh ref={meshRef} castShadow receiveShadow position={[0, -0.1, 0]}>
        <capsuleGeometry args={[0.43, 0.9, 32, 64]} />
        <meshPhysicalMaterial 
          color={state.color} 
          roughness={state.roughness} 
          metalness={state.metalness}
          clearcoat={state.clearcoat}
          clearcoatRoughness={0.1}
          envMapIntensity={1.5}
        />

        {state.logos.front && (
          <LogoDecal
            url={state.logos.front}
            position={[0, 0.28, 0.43]}
            rotation={[0, 0, 0]}
            scale={state.logoScale}
          />
        )}

        {state.logos.back && (
          <LogoDecal
            url={state.logos.back}
            position={[0, 0.28, -0.43]}
            rotation={[0, Math.PI, 0]}
            scale={state.logoScale}
          />
        )}
      </mesh>

      <group>
        <mesh position={[0.5, 0.38, 0]} rotation={[0, 0, -0.6]}>
          <cylinderGeometry args={[0.15, state.type === 'long_sleeve' ? 0.1 : 0.17, state.type === 'long_sleeve' ? 1.1 : 0.4, 32]} />
          <meshPhysicalMaterial color={state.color} roughness={state.roughness} metalness={state.metalness} clearcoat={state.clearcoat} />
          {state.logos.leftSleeve && (
            <LogoDecal
              url={state.logos.leftSleeve}
              position={[0.15, 0, 0]}
              rotation={[0, Math.PI / 2, 0]}
              scale={state.logoScale * 0.35}
            />
          )}
        </mesh>

        <mesh position={[-0.5, 0.38, 0]} rotation={[0, 0, 0.6]}>
          <cylinderGeometry args={[0.15, state.type === 'long_sleeve' ? 0.1 : 0.17, state.type === 'long_sleeve' ? 1.1 : 0.4, 32]} />
          <meshPhysicalMaterial color={state.color} roughness={state.roughness} metalness={state.metalness} clearcoat={state.clearcoat} />
          {state.logos.rightSleeve && (
            <LogoDecal
              url={state.logos.rightSleeve}
              position={[-0.15, 0, 0]}
              rotation={[0, -Math.PI / 2, 0]}
              scale={state.logoScale * 0.35}
            />
          )}
        </mesh>
      </group>

      {state.type === 'polo' && (
        <group position={[0, 0.78, 0]}>
          <mesh rotation={[0.2, 0, 0]}>
            <torusGeometry args={[0.18, 0.06, 16, 40, Math.PI * 1.5]} />
            <meshPhysicalMaterial color={state.color} roughness={state.roughness} metalness={state.metalness} clearcoat={state.clearcoat} />
          </mesh>
        </group>
      )}

      {state.type === 'hoodie' && (
        <mesh position={[0, 0.82, -0.1]} rotation={[-0.45, 0, 0]}>
          <sphereGeometry args={[0.34, 32, 32, 0, Math.PI * 2, 0, Math.PI * 0.75]} />
          <meshPhysicalMaterial color={state.color} roughness={state.roughness} metalness={state.metalness} clearcoat={state.clearcoat} />
        </mesh>
      )}
    </group>
  );
};

